// ROV Control Architecture Initialization
// 20 Hz control loop (Δt = 0.05 s)

const DT = 0.05;  // Time step (s)
const T_END = 10.0;  // Mission end time (s) - adjust as needed
const CONTROL_FREQ = 20;  // Hz

// Mission waypoints [x, y, z, dwell_time]
const waypoints = [
  [0, 0, -5, 2.0],
  [10, 0, -5, 1.0],
  [10, 10, -10, 1.5],
  [0, 10, -10, 1.0],
  [0, 0, -5, 0.0]
];

// ROV initial state [x, y, z, roll, pitch, yaw, vx, vy, vz, wx, wy, wz]
const state = {
  position: [0, 0, 0],  // [x, y, z]
  attitude: [0, 0, 0],  // [roll, pitch, yaw]
  velocity: [0, 0, 0],  // [vx, vy, vz]
  angular_velocity: [0, 0, 0]  // [wx, wy, wz]
};

// Mission Planning Agent state
const missionAgent = {
  currentWaypointIndex: 0,
  dwellStartTime: null,
  isDwelling: false,
  waypointsReached: 0
};

// Sonar Agent parameters (16-beam multibeam)
const sonarAgent = {
  numBeams: 16,
  maxRange: 20.0,  // meters
  fov: 120,  // degrees
  detections: []
};

// Navigation Agent parameters (PD controller + APF)
const navAgent = {
  kp_pos: 2.0,  // Position proportional gain
  kd_pos: 1.5,  // Position derivative gain
  kp_yaw: 1.0,  // Yaw proportional gain
  kd_yaw: 0.5,  // Yaw derivative gain
  apf_gain: 5.0,  // Artificial potential field gain
  apf_range: 3.0,  // APF activation range (m)
  thrust: [0, 0, 0, 0]  // [Fx, Fy, Fz, Mz]
};

// Fault Monitoring Agent thresholds
const faultAgent = {
  thrusterDegradationThreshold: 0.7,  // 70% efficiency
  overspeedThreshold: 2.0,  // m/s
  saturationThreshold: 0.95,  // 95% of max thrust
  faultDetected: false,
  faultType: null,
  safeModeActive: false,
  thrusterEfficiency: [1.0, 1.0, 1.0, 1.0]  // Per-thruster efficiency
};

// Communication Agent parameters
const commAgent = {
  packetLossRate: 0.05,  // 5%
  latencyMin: 0.1,  // seconds
  latencyMax: 0.5,  // seconds
  packetsTransmitted: 0,
  packetsLost: 0,
  telemetryLog: []
};

// Hydrodynamic parameters
const hydro = {
  mass: 50.0,  // kg
  drag_linear: [10, 10, 15],  // Linear drag coefficients [x, y, z]
  drag_quadratic: [20, 20, 30],  // Quadratic drag coefficients
  inertia_z: 5.0  // Yaw moment of inertia
};

// Mission state
const mission = {
  time: 0.0,
  iteration: 0,
  trajectoryLog: [],
  telemetryLog: []
};

return [{
  json: {
    DT,
    T_END,
    CONTROL_FREQ,
    waypoints,
    state,
    missionAgent,
    sonarAgent,
    navAgent,
    faultAgent,
    commAgent,
    hydro,
    mission
  }
}];

// Post-mission performance analysis
const data = $input.first().json;

const trajectoryLog = data.mission.trajectoryLog;
const telemetryLog = data.commAgent.telemetryLog;
const waypoints = data.waypoints;

// Calculate total distance traveled
let totalDistance = 0;
for (let i = 1; i < trajectoryLog.length; i++) {
  const p1 = trajectoryLog[i - 1].position;
  const p2 = trajectoryLog[i].position;
  const dx = p2[0] - p1[0];
  const dy = p2[1] - p1[1];
  const dz = p2[2] - p1[2];
  totalDistance += Math.sqrt(dx * dx + dy * dy + dz * dz);
}

// Calculate average speed
const avgSpeed = trajectoryLog.reduce((sum, entry) => {
  const v = entry.velocity;
  return sum + Math.sqrt(v[0] ** 2 + v[1] ** 2 + v[2] ** 2);
}, 0) / trajectoryLog.length;

// Waypoint completion rate
const waypointsReached = data.missionAgent.waypointsReached;
const completionRate = (waypointsReached / waypoints.length) * 100;

// Communication statistics
const packetsTransmitted = data.commAgent.packetsTransmitted;
const packetsLost = data.commAgent.packetsLost;
const packetLossRate = (packetsLost / packetsTransmitted) * 100;

// Fault statistics
const faultDetected = data.faultAgent.faultDetected;
const faultType = data.faultAgent.faultType;

const performanceReport = {
  missionDuration: data.mission.time,
  totalIterations: data.mission.iteration,
  totalDistance: totalDistance,
  averageSpeed: avgSpeed,
  waypointsReached: waypointsReached,
  waypointCompletionRate: completionRate,
  packetsTransmitted: packetsTransmitted,
  packetsLost: packetsLost,
  packetLossRate: packetLossRate,
  faultDetected: faultDetected,
  faultType: faultType,
  finalPosition: data.state.position,
  finalVelocity: data.state.velocity
};

data.performanceReport = performanceReport;

return [{ json: data }];

// Sonar Agent: 16-beam multibeam sonar simulation
const data = $input.first().json;

const numBeams = data.sonarAgent.numBeams;
const maxRange = data.sonarAgent.maxRange;
const fov = data.sonarAgent.fov;
const position = data.state.position;
const yaw = data.state.attitude[2];

// Simulate obstacle detection (simplified)
const detections = [];
for (let i = 0; i < numBeams; i++) {
  const beamAngle = yaw + (fov / 2) * (Math.PI / 180) * (2 * i / (numBeams - 1) - 1);

  // Simulate random obstacles with 10% detection probability
  if (Math.random() < 0.1) {
    const range = Math.random() * maxRange;
    const bearing = beamAngle;
    detections.push({
      beam: i,
      range: range,
      bearing: bearing,
      x: position[0] + range * Math.cos(bearing),
      y: position[1] + range * Math.sin(bearing)
    });
  }
}

data.sonarAgent.detections = detections;

return [{ json: data }];

// Mission Planning Agent: Waypoint management and dwell operations
const data = $input.first().json;

const waypoints = data.waypoints;
const missionAgent = data.missionAgent;
const position = data.state.position;
const time = data.mission.time;

const currentWpIdx = missionAgent.currentWaypointIndex;

if (currentWpIdx >= waypoints.length) {
  // Mission complete
  data.missionAgent.missionComplete = true;
  return [{ json: data }];
}

const targetWp = waypoints[currentWpIdx];
const targetPos = [targetWp[0], targetWp[1], targetWp[2]];
const dwellTime = targetWp[3];

// Calculate distance to waypoint
const dx = targetPos[0] - position[0];
const dy = targetPos[1] - position[1];
const dz = targetPos[2] - position[2];
const distance = Math.sqrt(dx * dx + dy * dy + dz * dz);

const WAYPOINT_THRESHOLD = 0.5;  // meters

// Check if waypoint reached
if (distance < WAYPOINT_THRESHOLD) {
  if (!missionAgent.isDwelling && dwellTime > 0) {
    // Start dwell
    missionAgent.isDwelling = true;
    missionAgent.dwellStartTime = time;
  } else if (missionAgent.isDwelling) {
    // Check if dwell complete
    const dwellElapsed = time - missionAgent.dwellStartTime;
    if (dwellElapsed >= dwellTime) {
      // Move to next waypoint
      missionAgent.currentWaypointIndex++;
      missionAgent.waypointsReached++;
      missionAgent.isDwelling = false;
      missionAgent.dwellStartTime = null;
    }
  } else {
    // No dwell required, move to next waypoint
    missionAgent.currentWaypointIndex++;
    missionAgent.waypointsReached++;
  }
}

data.missionAgent.targetWaypoint = targetPos;
data.missionAgent.distanceToWaypoint = distance;

return [{ json: data }];

// Navigation Agent: PD position control + Artificial Potential Field
const data = $input.first().json;

const navAgent = data.navAgent;
const state = data.state;
const missionAgent = data.missionAgent;
const sonarDetections = data.sonarAgent.detections;

const position = state.position;
const velocity = state.velocity;
const yaw = state.attitude[2];
const targetPos = missionAgent.targetWaypoint || [0, 0, -5];

// PD position control
const kp = navAgent.kp_pos;
const kd = navAgent.kd_pos;

const error_x = targetPos[0] - position[0];
const error_y = targetPos[1] - position[1];
const error_z = targetPos[2] - position[2];

let Fx = kp * error_x - kd * velocity[0];
let Fy = kp * error_y - kd * velocity[1];
let Fz = kp * error_z - kd * velocity[2];

// Artificial Potential Field obstacle avoidance
const apf_gain = navAgent.apf_gain;
const apf_range = navAgent.apf_range;

for (const detection of sonarDetections) {
  if (detection.range < apf_range) {
    const repulsion = apf_gain * (1.0 / detection.range - 1.0 / apf_range);
    const angle = detection.bearing;
    Fx -= repulsion * Math.cos(angle);
    Fy -= repulsion * Math.sin(angle);
  }
}

// Yaw control (simple heading to target)
const desired_yaw = Math.atan2(error_y, error_x);
const yaw_error = desired_yaw - yaw;
const Mz = navAgent.kp_yaw * yaw_error - navAgent.kd_yaw * state.angular_velocity[2];

// Store thrust commands
navAgent.thrust = [Fx, Fy, Fz, Mz];
data.navAgent = navAgent;

return [{ json: data }];

// Fault Monitoring Agent: Thruster degradation, overspeed, saturation
const data = $input.first().json;

const faultAgent = data.faultAgent;
const state = data.state;
const thrust = data.navAgent.thrust;

// Check thruster degradation (simulate random degradation)
if (Math.random() < 0.01) {
  const thrusterIdx = Math.floor(Math.random() * 4);
  faultAgent.thrusterEfficiency[thrusterIdx] *= 0.95;
}

// Check for degraded thrusters
const minEfficiency = Math.min(...faultAgent.thrusterEfficiency);
if (minEfficiency < faultAgent.thrusterDegradationThreshold) {
  faultAgent.faultDetected = true;
  faultAgent.faultType = 'thruster_degradation';
  faultAgent.safeModeActive = true;
}

// Check overspeed
const speed = Math.sqrt(
  state.velocity[0] ** 2 + 
  state.velocity[1] ** 2 + 
  state.velocity[2] ** 2
);
if (speed > faultAgent.overspeedThreshold) {
  faultAgent.faultDetected = true;
  faultAgent.faultType = 'overspeed';
  faultAgent.safeModeActive = true;
}

// Check actuator saturation
const MAX_THRUST = 100.0;
const thrustMag = Math.sqrt(
  thrust[0] ** 2 + thrust[1] ** 2 + thrust[2] ** 2
);
if (thrustMag > MAX_THRUST * faultAgent.saturationThreshold) {
  faultAgent.faultDetected = true;
  faultAgent.faultType = 'actuator_saturation';
  faultAgent.safeModeActive = true;
}

data.faultAgent = faultAgent;

return [{ json: data }];

// Safe Mode: Scale thrust commands to safe levels
const data = $input.first().json;

const SAFE_MODE_SCALE = 0.5;  // Reduce thrust to 50%
const thrust = data.navAgent.thrust;

data.navAgent.thrust = [
  thrust[0] * SAFE_MODE_SCALE,
  thrust[1] * SAFE_MODE_SCALE,
  thrust[2] * SAFE_MODE_SCALE,
  thrust[3] * SAFE_MODE_SCALE
];

data.faultAgent.thrustScaled = true;

return [{ json: data }];

// 6-DOF Dynamics Integration with Euler method and quadratic drag
const data = $input.first().json;

const DT = data.DT;
const state = data.state;
const thrust = data.navAgent.thrust;
const hydro = data.hydro;
const faultAgent = data.faultAgent;

// Apply thruster efficiency
const eff = faultAgent.thrusterEfficiency;
const Fx = thrust[0] * eff[0];
const Fy = thrust[1] * eff[1];
const Fz = thrust[2] * eff[2];
const Mz = thrust[3] * eff[3];

// Current state
const vx = state.velocity[0];
const vy = state.velocity[1];
const vz = state.velocity[2];
const wz = state.angular_velocity[2];

// Quadratic hydrodynamic drag
const drag_x = -hydro.drag_linear[0] * vx - hydro.drag_quadratic[0] * vx * Math.abs(vx);
const drag_y = -hydro.drag_linear[1] * vy - hydro.drag_quadratic[1] * vy * Math.abs(vy);
const drag_z = -hydro.drag_linear[2] * vz - hydro.drag_quadratic[2] * vz * Math.abs(vz);

// Acceleration (F = ma)
const ax = (Fx + drag_x) / hydro.mass;
const ay = (Fy + drag_y) / hydro.mass;
const az = (Fz + drag_z) / hydro.mass;

// Angular acceleration (M = I * alpha)
const alpha_z = Mz / hydro.inertia_z;

// Euler integration
state.velocity[0] += ax * DT;
state.velocity[1] += ay * DT;
state.velocity[2] += az * DT;
state.angular_velocity[2] += alpha_z * DT;

state.position[0] += state.velocity[0] * DT;
state.position[1] += state.velocity[1] * DT;
state.position[2] += state.velocity[2] * DT;
state.attitude[2] += state.angular_velocity[2] * DT;

// Normalize yaw to [-pi, pi]
while (state.attitude[2] > Math.PI) state.attitude[2] -= 2 * Math.PI;
while (state.attitude[2] < -Math.PI) state.attitude[2] += 2 * Math.PI;

// Update mission time and iteration
data.mission.time += DT;
data.mission.iteration++;

// Log trajectory
data.mission.trajectoryLog.push({
  time: data.mission.time,
  position: [...state.position],
  velocity: [...state.velocity],
  attitude: [...state.attitude]
});

data.state = state;

return [{ json: data }];

// Communication Agent: Package and transmit telemetry
const data = $input.first().json;
const commAgent = data.commAgent;

// Simulate packet loss (5%)
const packetLost = Math.random() < commAgent.packetLossRate;

commAgent.packetsTransmitted++;
if (packetLost) {
  commAgent.packetsLost++;
}

// Simulate latency jitter
const latency = commAgent.latencyMin + 
  Math.random() * (commAgent.latencyMax - commAgent.latencyMin);

// Package telemetry
const telemetryPacket = {
  time: data.mission.time,
  position: [...data.state.position],
  velocity: [...data.state.velocity],
  thrust: [...data.navAgent.thrust],
  faults: data.faultAgent.faultDetected,
  waypoint: data.missionAgent.currentWaypointIndex,
  packet_id: commAgent.packetsTransmitted,
  packetLost: packetLost,
  latency: latency
};

// Log telemetry
commAgent.telemetryLog.push(telemetryPacket);
data.commAgent = commAgent;

return [{ json: data }];
